import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useImperativeHandle,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { createPortal } from 'react-dom';
import type { Placement, PositionResult } from '@o9ds/core';
import { computePosition, createPositionWatcher, filterItems, filterGroups } from '@o9ds/core';
import type { ListItemBase, ListGroup } from '@o9ds/core';
import { useOverlay } from '../../hooks/useOverlay';
import { useTooltip } from '../../hooks/useTooltip';
import { FormLabel } from '../FormLabel';
import O9IconButton from '../IconButton/IconButton';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ComboboxOptionData extends ListItemBase {
  value: unknown;
}

export interface O9ComboboxProps {
  items: ComboboxOptionData[] | ListGroup<ComboboxOptionData>[];
  value?: unknown;
  defaultValue?: unknown;
  inputValue?: string;
  placeholder?: string;
  label?: string;
  isDisabled?: boolean;
  isRequired?: boolean;
  isInvalid?: boolean;
  errorMsg?: string;
  isInlineError?: boolean;
  size?: 'sm' | 'lg';
  isClearable?: boolean;
  isLoading?: boolean;
  isReadOnly?: boolean;
  isFullWidth?: boolean;
  width?: string;
  placement?: 'top-start' | 'top-end' | 'bottom-start' | 'bottom-end' | 'auto';
  maxHeight?: string;
  hasGroupDividers?: boolean;
  filterFn?: (item: ComboboxOptionData, query: string) => boolean;
  isOpen?: boolean;
  defaultOpen?: boolean;
  onChange?: (item: ComboboxOptionData, index: number) => boolean | void;
  onInputChange?: (value: string) => void;
  onOpen?: () => boolean | void;
  onClose?: () => boolean | void;
  onClear?: (detail: { previousValue: unknown }) => void;
  onOpenChange?: (isOpen: boolean) => void;
  className?: string;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function isGrouped(
  items: ComboboxOptionData[] | ListGroup<ComboboxOptionData>[],
): items is ListGroup<ComboboxOptionData>[] {
  return items.length > 0 && 'items' in items[0];
}

function flattenItems(
  items: ComboboxOptionData[] | ListGroup<ComboboxOptionData>[],
): ComboboxOptionData[] {
  if (isGrouped(items)) return items.flatMap((g) => g.items);
  return items as ComboboxOptionData[];
}

function applyFilter(
  items: ComboboxOptionData[] | ListGroup<ComboboxOptionData>[],
  query: string,
  filterFn?: (item: ComboboxOptionData, query: string) => boolean,
): ComboboxOptionData[] | ListGroup<ComboboxOptionData>[] {
  if (!query) return items;

  if (filterFn) {
    if (isGrouped(items)) {
      const result: ListGroup<ComboboxOptionData>[] = [];
      for (const group of items) {
        const filtered = group.items.filter((item) => filterFn(item, query));
        if (filtered.length > 0) {
          result.push({ ...group, items: filtered });
        }
      }
      return result;
    }
    return (items as ComboboxOptionData[]).filter((item) => filterFn(item, query));
  }

  if (isGrouped(items)) {
    return filterGroups(items, { query });
  }
  return filterItems(items as ComboboxOptionData[], { query });
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9Combobox = forwardRef<HTMLDivElement, O9ComboboxProps>(
  function O9Combobox(
    {
      items,
      value,
      defaultValue,
      inputValue: inputValueProp,
      placeholder,
      label,
      isDisabled = false,
      isRequired = false,
      isInvalid = false,
      errorMsg,
      isInlineError = false,
      size = 'lg',
      isClearable = true,
      isLoading = false,
      isReadOnly = false,
      isFullWidth = false,
      width,
      placement = 'bottom-start',
      maxHeight,
      hasGroupDividers = true,
      filterFn,
      isOpen: openProp,
      defaultOpen = false,
      onChange,
      onInputChange,
      onOpen,
      onClose,
      onClear,
      onOpenChange,
      className,
    },
    ref,
  ) {
    const uid = useId();
    const comboId = `o9ds-combobox-${uid}`;
    const panelId = `${comboId}-panel`;
    const labelId = `${comboId}-lbl`;
    const inputId = `${comboId}-input`;
    const errorId = `${comboId}-err`;

    const rootRef = useRef<HTMLDivElement>(null);
    const fieldRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);
    const actionsRef = useRef<HTMLDivElement>(null);
    const panelRef = useRef<HTMLDivElement>(null);
    const errIcoRef = useRef<HTMLSpanElement>(null);

    useImperativeHandle(ref, () => rootRef.current!, []);

    useTooltip({
      triggerRef: errIcoRef,
      tooltip: isInlineError && isInvalid && errorMsg ? errorMsg : undefined,
    });

    // ── Controlled / Uncontrolled open ─────────────────────────────────
    const isOpenControlled = openProp !== undefined;
    const [internalOpen, setInternalOpen] = useState(defaultOpen);
    const isOpen = isOpenControlled ? openProp! : internalOpen;

    const setOpen = useCallback(
      (next: boolean) => {
        if (!isOpenControlled) setInternalOpen(next);
        onOpenChange?.(next);
      },
      [isOpenControlled, onOpenChange],
    );

    // ── Controlled / Uncontrolled value ────────────────────────────────
    const isValueControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState<unknown>(
      defaultValue ?? null,
    );
    const currentValue = isValueControlled ? value : internalValue;

    // ── Input text state ─────────────────────────────────────────────
    const isInputControlled = inputValueProp !== undefined;
    const [internalInputValue, setInternalInputValue] = useState(() => {
      if (inputValueProp !== undefined) return inputValueProp;
      const initValue = value ?? defaultValue ?? null;
      if (initValue != null) {
        const allFlat = flattenItems(items);
        const found = allFlat.find((item) => item.value === initValue);
        return found?.label ?? '';
      }
      return '';
    });
    const currentInputValue = isInputControlled ? inputValueProp : internalInputValue;

    // Sync internal input value when controlled value changes externally
    useEffect(() => {
      if (isInputControlled || !isValueControlled) return;
      const allFlat = flattenItems(items);
      const found = allFlat.find((item) => item.value === value);
      setInternalInputValue(found?.label ?? '');
    }, [value, items, isValueControlled, isInputControlled]);

    // ── Active index ────────────────────────────────────────────────
    const [activeIndex, setActiveIndex] = useState(-1);
    const keyboardActiveRef = useRef(false);

    // ── Overlay hub ────────────────────────────────────────────────────
    const overlay = useOverlay();

    // Ref to track if we should prevent close on blur
    const preventCloseRef = useRef(false);
    const closingRef = useRef(false);
    const isUserTypingRef = useRef(false);

    // ── Filtered items ──────────────────────────────────────────────
    const filteredItems = useMemo(
      () => isUserTypingRef.current ? applyFilter(items, currentInputValue, filterFn) : items,
      [items, currentInputValue, filterFn],
    );

    const flatItems = useMemo(
      () => flattenItems(filteredItems),
      [filteredItems],
    );

    // ── Selected item lookup (against unfiltered list) ──────────────
    const selectedItem = useMemo(() => {
      if (currentValue == null) return null;
      const allFlat = flattenItems(items);
      return allFlat.find((item) => item.value === currentValue) ?? null;
    }, [currentValue, items]);

    // ── Close handler ──────────────────────────────────────────────────
    const handleClose = useCallback(
      (revertInput = true) => {
        if (!isOpen) return;
        if (closingRef.current) return;
        closingRef.current = true;

        if (onClose?.() === false) {
          closingRef.current = false;
          return;
        }

        isUserTypingRef.current = false;
        setOpen(false);
        overlay.close(comboId);

        if (revertInput && !isInputControlled) {
          setInternalInputValue(selectedItem?.label ?? '');
        }

        rootRef.current?.dispatchEvent(
          new CustomEvent('combobox:close', { bubbles: true, cancelable: true }),
        );
        closingRef.current = false;
      },
      [isOpen, onClose, setOpen, overlay, comboId, isInputControlled, selectedItem],
    );

    // ── Open handler ───────────────────────────────────────────────────
    const handleOpen = useCallback(() => {
      if (isOpen || isDisabled || isLoading || isReadOnly) return;
      if (onOpen?.() === false) return;

      setOpen(true);
      rootRef.current?.dispatchEvent(
        new CustomEvent('combobox:open', { bubbles: true, cancelable: true }),
      );
    }, [isOpen, isDisabled, isLoading, isReadOnly, onOpen, setOpen]);

    // ── Selection handler ──────────────────────────────────────────────
    const handleSelect = useCallback(
      (item: ComboboxOptionData, index: number) => {
        if (item.isDisabled) return;
        const result = onChange?.(item, index);

        isUserTypingRef.current = false;

        if (!isValueControlled) {
          setInternalValue(item.value);
        }
        if (!isInputControlled) {
          setInternalInputValue(item.label);
        }

        rootRef.current?.dispatchEvent(
          new CustomEvent('combobox:change', {
            bubbles: true,
            cancelable: true,
            detail: { item, index },
          }),
        );

        if (result !== false) {
          handleClose(false);
        }
      },
      [onChange, isValueControlled, isInputControlled, handleClose],
    );

    // Reset active index when panel opens or filtered items change
    useEffect(() => {
      if (isOpen && flatItems.length > 0) {
        keyboardActiveRef.current = false;
        const firstEnabled = flatItems.findIndex((item) => !item.isDisabled);
        setActiveIndex(firstEnabled >= 0 ? firstEnabled : 0);
      } else if (isOpen && flatItems.length === 0) {
        setActiveIndex(-1);
      }
    }, [isOpen, flatItems]);

    // ── Item click handler ─────────────────────────────────────────────
    const handleItemClick = useCallback(
      (item: ComboboxOptionData, flatIndex: number) => {
        if (item.isDisabled || isLoading) return;
        preventCloseRef.current = true;
        setActiveIndex(flatIndex);
        handleSelect(item, flatIndex);
      },
      [isLoading, handleSelect],
    );

    // ── Clear handler ──────────────────────────────────────────────────
    const handleClear = useCallback(
      (e: React.MouseEvent<HTMLButtonElement>) => {
        e.stopPropagation();
        isUserTypingRef.current = false;
        const previousValue = currentValue;
        if (!isValueControlled) {
          setInternalValue(null);
        }
        if (!isInputControlled) {
          setInternalInputValue('');
        }
        onClear?.({ previousValue });
        rootRef.current?.dispatchEvent(
          new CustomEvent('combobox:clear', {
            bubbles: true,
            detail: { previousValue },
          }),
        );
        inputRef.current?.focus({ preventScroll: true });
      },
      [currentValue, isValueControlled, isInputControlled, onClear],
    );

    // ── Chevron click handler ────────────────────────────────────────
    const handleChevronClick = useCallback(
      (e: React.MouseEvent) => {
        e.stopPropagation();
        if (isDisabled || isLoading || isReadOnly) return;
        if (isOpen) {
          handleClose();
        } else {
          handleOpen();
          requestAnimationFrame(() => {
            inputRef.current?.focus({ preventScroll: true });
          });
        }
      },
      [isDisabled, isLoading, isReadOnly, isOpen, handleOpen, handleClose],
    );

    // ── Input change handler ─────────────────────────────────────────
    const handleInputChange = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const text = e.target.value;
        isUserTypingRef.current = true;
        if (!isInputControlled) {
          setInternalInputValue(text);
        }
        onInputChange?.(text);

        // Clear selection when user edits text
        if (currentValue != null) {
          const matchesSelection = selectedItem?.label === text;
          if (!matchesSelection && !isValueControlled) {
            setInternalValue(null);
          }
        }

        rootRef.current?.dispatchEvent(
          new CustomEvent('combobox:input', {
            bubbles: true,
            detail: { value: text },
          }),
        );

        // Open panel on typing
        if (!isOpen && text.length > 0) {
          handleOpen();
        }
      },
      [
        isInputControlled,
        onInputChange,
        currentValue,
        selectedItem,
        isValueControlled,
        isOpen,
        handleOpen,
      ],
    );

    // ── Overlay hub registration ───────────────────────────────────────
    useEffect(() => {
      if (!isOpen || !panelRef.current) return;
      overlay.open({
        id: comboId,
        type: 'dropdown',
        element: panelRef.current,
        triggerElement: inputRef.current ?? undefined,
        priority: 20,
        config: { autoCloseOnOutsideClick: true },
        onClose: handleClose,
      });
      return () => {
        overlay.close(comboId);
      };
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen]);

    // ── Positioning (imperative — bypasses React state to avoid flicker) ─
    const posRef = useRef<PositionResult | null>(null);
    const posWatcherRef = useRef<ReturnType<typeof createPositionWatcher> | null>(null);

    useLayoutEffect(() => {
      if (!isOpen) {
        posRef.current = null;
        posWatcherRef.current?.destroy();
        posWatcherRef.current = null;
        return;
      }

      const anchor = fieldRef.current;
      const float = panelRef.current;
      if (!anchor || !float) return;

      const opts = { placement: placement as Placement, gap: 2, width: 'anchor' as const };

      const applyPosition = (pos: PositionResult) => {
        float.style.transform = `translate(${pos.x}px, ${pos.y}px)`;
        if (pos.width) {
          float.style.width = pos.width;
          float.style.minWidth = pos.width;
        }
        if (pos.maxHeight != null) {
          float.style.maxHeight = `${pos.maxHeight}px`;
        }
      };

      // Pre-set the panel width to the anchor's width so computePosition
      // measures the float at its actual display width (not CSS min-width: 100%
      // which resolves to the viewport width for portaled absolutely-positioned
      // elements, causing horizontal clamping to produce a wrong x).
      const anchorWidth = `${anchor.getBoundingClientRect().width}px`;
      float.style.width = anchorWidth;
      float.style.minWidth = anchorWidth;

      const pos = computePosition(anchor, float, opts);
      posRef.current = pos;
      applyPosition(pos);
      float.style.visibility = '';

      const watcher = createPositionWatcher(anchor, float, opts, (result) => {
        posRef.current = result;
        applyPosition(result);
      });
      posWatcherRef.current = watcher;

      return () => {
        watcher.destroy();
        posWatcherRef.current = null;
      };
    }, [isOpen, placement]);

    // ── Outside click ──────────────────────────────────────────────────
    useEffect(() => {
      if (!isOpen) return;
      const onPointerDown = (e: PointerEvent) => {
        const target = e.target as Node;
        if (panelRef.current?.contains(target)) return;
        if (rootRef.current?.contains(target)) return;
        handleClose();
      };
      document.addEventListener('pointerdown', onPointerDown, true);
      return () =>
        document.removeEventListener('pointerdown', onPointerDown, true);
    }, [isOpen, handleClose]);

    // ── Focus guard — close if focus escapes component scope ────────
    useEffect(() => {
      if (!isOpen) return;
      const onFocusIn = (e: FocusEvent) => {
        const target = e.target as Node;
        if (rootRef.current?.contains(target)) return;
        if (panelRef.current?.contains(target)) return;
        handleClose();
      };
      document.addEventListener('focusin', onFocusIn);
      return () => document.removeEventListener('focusin', onFocusIn);
    }, [isOpen, handleClose]);

    // ── Blur with delay ──────────────────────────────────────────────
    const blurTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    const handleInputBlur = useCallback(() => {
      if (preventCloseRef.current) {
        preventCloseRef.current = false;
        return;
      }
      blurTimeoutRef.current = setTimeout(() => {
        if (isOpen) handleClose();
      }, 100);
    }, [isOpen, handleClose]);

    const handleInputFocus = useCallback(() => {
      if (blurTimeoutRef.current) {
        clearTimeout(blurTimeoutRef.current);
        blurTimeoutRef.current = null;
      }
    }, []);

    useEffect(() => {
      return () => {
        if (blurTimeoutRef.current) clearTimeout(blurTimeoutRef.current);
      };
    }, []);

    // ── Dynamic padding for actions overlay ──────────────────────────
    const updatePadding = useCallback(() => {
      if (!actionsRef.current || !fieldRef.current) return;
      const w = actionsRef.current.offsetWidth;
      const pad = w > 0 ? w + 4 : 0;
      fieldRef.current.style.setProperty('--o9ds-combobox-pad-r', `${pad}px`);
    }, []);

    useEffect(() => {
      updatePadding();
    });

    useEffect(() => {
      const el = actionsRef.current;
      if (!el) return;
      const obs = new ResizeObserver(updatePadding);
      obs.observe(el);
      return () => obs.disconnect();
    }, [updatePadding]);

    // ── Navigate helper (skip disabled) ──────────────────────────────
    const findNextEnabled = useCallback(
      (from: number, direction: 1 | -1): number => {
        const len = flatItems.length;
        if (len === 0) return -1;
        let idx = from + direction;
        const isVisited = new Set<number>();
        while (idx >= 0 && idx < len && !isVisited.has(idx)) {
          isVisited.add(idx);
          if (!flatItems[idx].isDisabled) return idx;
          idx += direction;
        }
        return -1;
      },
      [flatItems],
    );

    // ── Keyboard handler ─────────────────────────────────────────────
    const handleKeyDown = useCallback(
      (e: React.KeyboardEvent) => {
        if (isDisabled || isLoading) return;

        switch (e.key) {
          case 'ArrowDown':
            e.preventDefault();
            if (!isOpen) {
              handleOpen();
            } else {
              keyboardActiveRef.current = true;
              const next = findNextEnabled(activeIndex, 1);
              if (next >= 0) setActiveIndex(next);
            }
            break;

          case 'ArrowUp':
            e.preventDefault();
            if (!isOpen) {
              handleOpen();
            } else {
              keyboardActiveRef.current = true;
              const prev = findNextEnabled(activeIndex, -1);
              if (prev >= 0) setActiveIndex(prev);
            }
            break;

          case 'Enter':
            if (isOpen && activeIndex >= 0 && activeIndex < flatItems.length) {
              e.preventDefault();
              const item = flatItems[activeIndex];
              if (!item.isDisabled) {
                handleSelect(item, activeIndex);
              }
            }
            break;

          case 'Escape':
            e.preventDefault();
            if (isOpen) {
              handleClose();
            } else {
              if (!isInputControlled) {
                setInternalInputValue('');
              }
              if (!isValueControlled) {
                setInternalValue(null);
              }
            }
            break;

          case 'Tab':
            if (isOpen) {
              e.preventDefault();
              if (activeIndex >= 0 && activeIndex < flatItems.length) {
                const item = flatItems[activeIndex];
                if (!item.isDisabled) {
                  handleSelect(item, activeIndex);
                  return;
                }
              }
              handleClose();
            }
            break;
        }
      },
      [
        isDisabled,
        isLoading,
        isOpen,
        activeIndex,
        flatItems,
        handleOpen,
        handleClose,
        handleSelect,
        findNextEnabled,
        isInputControlled,
        isValueControlled,
      ],
    );

    // ── Scroll active option into view ──────────────────────────────
    useEffect(() => {
      if (!isOpen || activeIndex < 0) return;
      const optEl = panelRef.current?.querySelector(
        `[data-index="${activeIndex}"]`,
      ) as HTMLElement | null;
      if (optEl && typeof optEl.scrollIntoView === 'function') {
        optEl.scrollIntoView({ block: 'nearest' });
      }
    }, [isOpen, activeIndex]);

    // ── CSS classes ────────────────────────────────────────────────────
    const hasValue = currentValue != null || currentInputValue.length > 0;
    const classes = [
      'o9ds-combobox',
      `o9ds-combobox--${size}`,
      isFullWidth && 'o9ds-combobox--full-width',
      isClearable && 'o9ds-combobox--clearable',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadOnly && 'is-readonly',
      isInvalid && 'has-error',
      isInvalid && isInlineError && 'error-inline',
      isOpen && 'open',
      hasValue && 'has-value',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // ── Width style ──────────────────────────────────────────────────
    const rootStyle: React.CSSProperties | undefined = (() => {
      const effectiveWidth = isFullWidth ? '100%' : width;
      if (!effectiveWidth) return undefined;
      return { '--o9ds-form-input-width': effectiveWidth } as React.CSSProperties;
    })();

    // ── Panel style ────────────────────────────────────────────────────
    // Initial render: visibility:hidden prevents any flash.
    // useLayoutEffect computes position and removes visibility before paint.
    const pos = posRef.current;
    const panelStyle: React.CSSProperties = {
      ...(pos
        ? {
            transform: `translate(${pos.x}px, ${pos.y}px)`,
            ...(pos.width ? { width: pos.width, minWidth: pos.width } : {}),
            ...(pos.maxHeight ? { maxHeight: `${pos.maxHeight}px` } : {}),
          }
        : { visibility: 'hidden' }),
      ...(maxHeight
        ? ({
            '--o9ds-combobox-panel-max-height': maxHeight,
          } as React.CSSProperties)
        : {}),
      ...(isLoading ? { pointerEvents: 'none' as const } : {}),
    };

    // ── Option rendering ───────────────────────────────────────────────
    const renderOption = (item: ComboboxOptionData, flatIndex: number) => {
      const isSelected = item.value === currentValue;
      const isHighlighted = flatIndex === activeIndex;
      const optClasses = [
        'o9ds-combobox__opt',
        item.isDisabled && 'is-disabled',
        isHighlighted && keyboardActiveRef.current && 'focused',
        isSelected && 'active',
      ]
        .filter(Boolean)
        .join(' ');

      return (
        <div
          key={item.id}
          id={`${comboId}-opt-${flatIndex}`}
          className={optClasses}
          role="option"
          aria-selected={isSelected}
          aria-disabled={item.isDisabled || undefined}
          data-index={flatIndex}
          onClick={() => handleItemClick(item, flatIndex)}
          onMouseEnter={() => {
            if (!item.isDisabled) {
              keyboardActiveRef.current = false;
              setActiveIndex(flatIndex);
            }
          }}
          onMouseDown={(e) => {
            e.preventDefault();
          }}
        >
          {item.icon && (
            <span
              className={`o9ds-combobox__opt__ico o9con o9con-${item.icon}`}
              aria-hidden="true"
            />
          )}
          <div className="o9ds-combobox__opt__txt">
            <span className="o9ds-combobox__opt__lbl">{item.label}</span>
          </div>
        </div>
      );
    };

    // ── Content rendering (flat vs grouped) ────────────────────────────
    const renderContent = () => {
      if (flatItems.length === 0) {
        return (
          <div className="o9ds-combobox__empty" role="status">
            No results
          </div>
        );
      }

      if (isGrouped(filteredItems)) {
        let flatIndex = 0;
        return (filteredItems as ListGroup<ComboboxOptionData>[]).map(
          (group, groupIdx) => (
            <div key={group.id} role="group" aria-label={group.label}>
              {groupIdx > 0 && hasGroupDividers && (
                <hr className="o9ds-combobox__divider" role="separator" />
              )}
              {group.label && (
                <div className="o9ds-combobox__hdr">{group.label}</div>
              )}
              {group.items.map((item) => {
                const node = renderOption(item, flatIndex);
                flatIndex++;
                return node;
              })}
            </div>
          ),
        );
      }

      return (filteredItems as ComboboxOptionData[]).map((item, i) =>
        renderOption(item, i),
      );
    };

    // ── Panel classes ──────────────────────────────────────────────────
    const panelClasses = [
      'o9ds-combobox__panel',
      isOpen && 'open',
    ].filter(Boolean).join(' ');

    // ── Panel (portaled) ───────────────────────────────────────────────
    const panel = isOpen
      ? createPortal(
          <div
            className={`o9ds-combobox o9ds-combobox--${size}`}
            style={{ display: 'contents' }}
          >
            <div
              ref={panelRef}
              id={panelId}
              className={panelClasses}
              role="listbox"
              aria-busy={isLoading || undefined}
              style={
                Object.keys(panelStyle).length > 0 ? panelStyle : undefined
              }
            >
              <div className="o9ds-combobox__scroll">{renderContent()}</div>
            </div>
          </div>,
          document.body,
        )
      : null;

    // ── Render ──────────────────────────────────────────────────────────
    return (
      <div ref={rootRef} className={classes} style={rootStyle}>
        {label && (
          <FormLabel
            htmlFor={inputId}
            id={labelId}
            size={size === 'sm' ? 'sm' : 'lg'}
            isRequired={isRequired}
            isDisabled={isDisabled}
            className="o9ds-combobox__lbl"
          >
            {label}
          </FormLabel>
        )}
        <div ref={fieldRef} className="o9ds-combobox__field">
          <input
            ref={inputRef}
            id={inputId}
            type="text"
            className="o9ds-combobox__input"
            role="combobox"
            value={currentInputValue}
            placeholder={placeholder}
            disabled={isDisabled}
            readOnly={isReadOnly}
            autoComplete="off"
            aria-haspopup="listbox"
            aria-expanded={isOpen}
            aria-controls={panelId}
            aria-activedescendant={
              isOpen && activeIndex >= 0
                ? `${comboId}-opt-${activeIndex}`
                : undefined
            }
            aria-autocomplete="list"
            aria-required={isRequired || undefined}
            aria-invalid={isInvalid || undefined}
            aria-busy={isLoading || undefined}
            aria-labelledby={label ? labelId : undefined}
            aria-describedby={isInvalid && errorMsg ? errorId : undefined}
            onChange={handleInputChange}
            onKeyDown={handleKeyDown}
            onBlur={handleInputBlur}
            onFocus={handleInputFocus}
          />
          <div ref={actionsRef} className="o9ds-combobox__actions">
            {isClearable && hasValue && !isDisabled && !isReadOnly && !isLoading && (
              <O9IconButton
                size="sm"
                variant="tertiary"
                icon="close"
                tooltip="Clear"
                aria-label="Clear"
                tabIndex={-1}
                onClick={handleClear}
                className="o9ds-combobox__clear"
              />
            )}
            {isClearable && hasValue && !isDisabled && !isReadOnly && !isLoading && (
              <span className="o9ds-combobox__sep" />
            )}
            {isInlineError && isInvalid && (
              <span ref={errIcoRef} className="o9ds-combobox__err-ico" aria-hidden="true" />
            )}
          </div>
          <O9IconButton
            size="sm"
            variant="tertiary"
            icon="angle-down"
            tooltip="Toggle menu"
            aria-label="Toggle menu"
            tabIndex={-1}
            onClick={handleChevronClick}
            isDisabled={isDisabled}
            className="o9ds-combobox__ico"
          />
          <div className="o9ds-combobox__border" />
        </div>
        {isInvalid && !isInlineError && errorMsg && (
          <div
            className="o9ds-inline-alert o9ds-inline-alert--error"
            id={errorId}
            role="alert"
          >
            <span className="o9ds-inline-alert__ico" aria-hidden="true" />
            <span className="o9ds-inline-alert__msg">{errorMsg}</span>
          </div>
        )}
        {panel}
      </div>
    );
  },
);

export { O9Combobox };
export default O9Combobox;
